1→import St from 'gi://St';
2→import Meta from 'gi://Meta';
3→import * as Main from 'resource:///org/gnome/shell/ui/main.js';
4→import * as Background from 'resource:///org/gnome/shell/ui/background.js';
5→
6→/// A `Pipeline` object is a handy way to manage the effects attached to an actor. It only manages
7→/// one actor at a time (so blurring multiple widgets will need multiple `Pipeline`), and is
8→/// linked to a `pipeline_id` that has been (hopefully) defined in the settings.
9→///
10→/// It communicates with the settings through the `PipelinesManager` object, and receives different
11→/// signals (with `pipeline_id` being an unique string):
12→/// - `'pipeline_id'::pipeline-updated`, handing a new pipeline descriptor object, when the pipeline
13→///   has been changed enough that it needs to rebuild the effects configuration
14→/// - `'pipeline_id'::pipeline-destroyed`, when the pipeline has been destroyed; thus making the
15→///   `Pipeline` change its id to `pipeline_default`
16→///
17→/// And each effect, with an unique `id`, is connected to the `PipelinesManager` for the signals:
18→/// - `'pipeline_id'::effect-'id'-key-removed`, handing the key that was removed
19→/// - `'pipeline_id'::effect-'id'-key-updated`, handing the key that was changed and its new value
20→/// - `'pipeline_id'::effect-'id'-key-added`, handing the key that was added and its value
21→export const Pipeline = class Pipeline {
22→    constructor(effects_manager, pipelines_manager, pipeline_id, actor = null, options = {}) {
23→        this.effects_manager = effects_manager;
24→        this.pipelines_manager = pipelines_manager;
25→        this.effects = [];
26→        this.effect_overrides = options.effect_overrides ?? {};
27→        this.set_pipeline_id(pipeline_id);
28→        this.attach_pipeline_to_actor(actor);
29→    }
30→
31→    /// Create a background linked to the monitor with index `monitor_index`, with a
32→    /// `BackgroundManager` that is appended to the list `background_managers`. The background actor
33→    /// will be given the name `widget_name` and inserted into the given `background_group`.
34→    /// If `use_absolute_position` is false, then the position used is at (0,0); useful when the
35→    /// positioning is relative.
36→    /// Note: exposed to public API.
37→    create_background_with_effects(
38→        monitor_index,
39→        background_managers,
40→        background_group,
41→        widget_name,
42→        use_absolute_position = true
43→    ) {
44→        let monitor = Main.layoutManager.monitors[monitor_index];
45→
46→        // create the new actor
47→        this.actor = new St.Widget({
48→            name: widget_name,
49→            x: use_absolute_position ? monitor.x : 0,
50→            y: .5 + (use_absolute_position ? monitor.y : 0), // add 1 to correct z-position
51→            z_position: 1, // seems to fix the multi-monitor glitch
52→            width: monitor.width,
53→            height: monitor.height
54→        });
55→
56→        // remove the effects, wether or not we attach the pipeline to the actor: if they are fired
57→        // while the actor has changed, this could go bad
58→        this.remove_all_effects();
59→        if (this.pipeline_id)
60→            this.attach_pipeline_to_actor(this.actor);
61→
62→        let bg_manager = new Background.BackgroundManager({
63→            container: this.actor,
64→            monitorIndex: monitor_index,
65→            controlPosition: false,
66→        });
67→        bg_manager._bms_pipeline = this;
68→
69→        // 'controlPosition: false' skips BackgroundManager's default layout pass, which also diables
70→        // sibling re-ordering.
71→        // Without it, new actors render on top while loading, causing a solid color flash through
72→        // on the surface.
73→        this.child_added_id = this.actor.connect(
74→            'child-added', (container, child) => {
75→                if (child instanceof Meta.BackgroundActor)
76→                    container.set_child_below_sibling(child, null);
77→            }
78→        );
79→
80→        background_managers.push(bg_manager);
81→        background_group.insert_child_at_index(this.actor, 0);
82→
83→        return this.actor;
84→    };
85→
86→    /// Set the pipeline id, correctly connecting the `Pipeline` object to listen the pipelines
87→    /// manager for pipeline-wide changes. This does not update the effects in consequence, call
88→    /// `change_pipeline_to` instead if you want to reconstruct the effects too.
89→    set_pipeline_id(pipeline_id) {
90→        // disconnect ancient signals
91→        this.remove_connections();
92→
93→        // change the id
94→        this.pipeline_id = pipeline_id;
95→
96→        // connect to settings changes
97→        this._pipeline_changed_id = this.pipelines_manager.connect(
98→            this.pipeline_id + '::pipeline-updated',
99→            (_, new_pipeline) => this.update_effects_from_pipeline(new_pipeline)
100→        );
101→        this._pipeline_destroyed_id = this.pipelines_manager.connect(
102→            this.pipeline_id + '::pipeline-destroyed',
103→            _ => this.change_pipeline_to("pipeline_default")
104→        );
105→    }
106→
107→    /// Disconnect the signals for the pipeline changes. Please note that the signals related to the
108→    /// effects are stored with them and removed with `remove_all_effects`.
109→    remove_connections() {
110→        if (this._pipeline_changed_id)
111→            this.pipelines_manager.disconnect(this._pipeline_changed_id);
112→        if (this._pipeline_destroyed_id)
113→            this.pipelines_manager.disconnect(this._pipeline_destroyed_id);
114→        this._pipeline_changed_id = null;
115→        this._pipeline_destroyed_id = null;
116→    }
117→
118→    /// Attach a Pipeline object with `pipeline_id` already set to an actor.
119→    attach_pipeline_to_actor(actor) {
120→        // set the actor
121→        if (actor)
122→            this.actor = actor;
123→        else {
124→            this.remove_pipeline_from_actor();
125→            return;
126→        }
127→
128→        // attach the pipeline
129→        let pipeline = this.pipelines_manager.pipelines[this.pipeline_id];
130→        if (!pipeline) {
131→            this._warn(`could not attach pipeline to actor, pipeline "${this.pipeline_id}" not found`);
132→            // do not recurse...
133→            if ("pipeline_default" in this.pipelines_manager.pipelines) {
134→                this.set_pipeline_id("pipeline_default");
135→                pipeline = this.pipelines_manager.pipelines["pipeline_default"];
136→            } else
137→                return;
138→        }
139→
140→        this.actor_destroy_id = this.actor.connect(
141→            "destroy", () => this.remove_pipeline_from_actor()
142→        );
143→
144→        // update the effects
145→        this.update_effects_from_pipeline(pipeline);
146→    }
147→
148→    remove_pipeline_from_actor() {
149→        this.remove_all_effects();
150→        if (this.actor && this.actor_destroy_id)
151→            this.actor.disconnect(this.actor_destroy_id);
152→        if (this.actor && this.child_added_id)
153→            this.actor.disconnect(this.child_added_id);
154→        this.actor_destroy_id = null;
155→        this.child_added_id = null;
156→        this.actor = null;
157→    }
158→
159→    /// Update the effects from the given pipeline object, the hard way.
160→    update_effects_from_pipeline(pipeline) {
161→        // remove all effects
162→        this.remove_all_effects();
163→
164→        // build the new effects to be added
165→        pipeline.effects.forEach(effect => {
166→            if ('new_' + effect.type + '_effect' in this.effects_manager)
167→                this.build_effect(effect);
168→            else
169→                this._warn(`could not add effect to actor, effect "${effect.type}" not found`);
170→        });
171→        this.effects.reverse();
172→
173→        // add the effects to the actor
174→        if (this.actor)
175→            this.effects.forEach(effect => this.actor.add_effect(effect));
176→        else
177→            this._warn(`could not add effect to actor, actor does not exist anymore`);
178→    }
179→
180→    /// Given an `effect_infos` object containing the effect type, id and params, build an effect
181→    /// and append it to the effects list
182→    build_effect(effect_infos) {
183→        const effect_params = this.get_effect_params(effect_infos);
184→        const effect_overrides = this.get_effect_overrides(effect_infos.type, effect_params);
185→        let effect = this.effects_manager['new_' + effect_infos.type + '_effect']({
186→            ...effect_params,
187→            ...effect_overrides,
188→        });
189→        effect._bms_effect_type = effect_infos.type;
190→        effect._bms_effect_params = effect_params;
191→        this.effects.push(effect);
192→
193→        // connect to settings changes
194→        effect._effect_key_removed_id = this.pipelines_manager.connect(
195→            this.pipeline_id + '::effect-' + effect_infos.id + '-key-removed', (_, key) => {
196→                effect._bms_effect_params[key] = effect.constructor.default_params[key];
197→                if (!this.apply_effect_override(effect, key))
198→                    effect[key] = effect.constructor.default_params[key];
199→            }
200→        );
201→        effect._effect_key_updated_id = this.pipelines_manager.connect(
202→            this.pipeline_id + '::effect-' + effect_infos.id + '-key-updated', (_, key, value) => {
203→                effect._bms_effect_params[key] = value;
204→                if (!this.apply_effect_override(effect, key))
205→                    effect[key] = value;
206→            }
207→        );
208→        effect._effect_key_added_id = this.pipelines_manager.connect(
209→            this.pipeline_id + '::effect-' + effect_infos.id + '-key-added', (_, key, value) => {
210→                effect._bms_effect_params[key] = value;
211→                if (!this.apply_effect_override(effect, key))
212→                    effect[key] = value;
213→            }
214→        );
215→    }
216→
217→    get_effect_params(effect_infos) {
218→        const effect_class = this.effects_manager.SUPPORTED_EFFECTS[effect_infos.type]?.class;
219→        return {
220→            ...(effect_class?.default_params ?? {}),
221→            ...effect_infos.params,
222→        };
223→    }
224→
225→    get_effect_overrides(effect_type, effect_params = {}) {
226→        const overrides = this.effect_overrides[effect_type] ?? {};
227→        return typeof overrides === 'function' ? overrides(effect_params) : overrides;
228→    }
229→
230→    apply_effect_override(effect, key) {
231→        const overrides = this.get_effect_overrides(effect._bms_effect_type, effect._bms_effect_params);
232→        if (!(key in overrides))
233→            return false;
234→
235→        effect[key] = overrides[key];
236→        return true;
237→    }
238→
239→    apply_effect_overrides(effect_type = null) {
240→        this.effects.forEach(effect => {
241→            if (effect_type && effect._bms_effect_type !== effect_type)
242→                return;
243→
244→            const overrides = this.get_effect_overrides(effect._bms_effect_type, effect._bms_effect_params);
245→            Object.keys(overrides).forEach(key => effect[key] = overrides[key]);
246→        });
247→    }
248→
249→    /// Remove every effect from the actor it is attached to. Please note that they are not
250→    /// destroyed, but rather stored (thanks to the `EffectManager` class) to be reused later.
251→    remove_all_effects() {
252→        this.effects.forEach(effect => {
253→            this.effects_manager.remove(effect);
254→            [
255→                effect._effect_key_removed_id,
256→                effect._effect_key_updated_id,
257→                effect._effect_key_added_id
258→            ].forEach(
259→                id => { if (id) this.pipelines_manager.disconnect(id); }
260→            );
261→            delete effect._effect_key_removed_id;
262→            delete effect._effect_key_updated_id;
263→            delete effect._effect_key_added_id;
264→            delete effect._bms_effect_type;
265→            delete effect._bms_effect_params;
266→        });
267→        this.effects = [];
268→    }
269→
270→    /// Change the pipeline id, and update the effects according to this change.
271→    /// Note: exposed to public API.
272→    change_pipeline_to(pipeline_id) {
273→        this.set_pipeline_id(pipeline_id);
274→        this.attach_pipeline_to_actor(this.actor);
275→    }
276→
277→    /// Resets the `Pipeline` object to a sane state, removing every effect and signal.
278→    /// Note: exposed to public API.
279→    destroy() {
280→        this.remove_all_effects();
281→        this.remove_connections();
282→        this.remove_pipeline_from_actor();
283→        this.pipeline_id = null;
284→    }
285→
286→    _warn(str) {
287→        console.warn(`[Blur my Shell > pipeline]     ${str}`);
288→    }
289→};
290→

