124→            return this._height;
125→        }
126→
127→        set height(value) {
128→            if (this._height !== value) {
129→                this._height = value;
130→
131→                this.set_uniform_value('height', parseFloat(this._height + 3.0 - 1e-6));
132→                this.update_radius();
133→            }
134→        }
135→
136→        get corners_top() {
137→            return this._corners_top;
138→        }
139→
140→        set corners_top(value) {
141→            if (this._corners_top !== value) {
142→                this._corners_top = value;
143→
144→                this.set_uniform_value('corners_top', this._corners_top ? 1 : 0);
145→            }
146→        }
147→
148→        get corners_bottom() {
149→            return this._corners_bottom;
150→        }
151→
152→        set corners_bottom(value) {
153→            if (this._corners_bottom !== value) {
154→                this._corners_bottom = value;
155→
156→                this.set_uniform_value('corners_bottom', this._corners_bottom ? 1 : 0);
157→            }
158→        }
159→
160→        get straight_corners() {
161→            return this._straight_corners;
162→        }
163→
164→        set straight_corners(value) {
165→            if (this._straight_corners !== value) {
166→                this._straight_corners = value;
167→
168→                this.set_uniform_value('straight_corners', this._straight_corners ? 1 : 0);
169→            }
170→        }
171→
172→        get clip() {
173→            return [this._clip_x0, this._clip_y0, this._clip_width, this._clip_height];
174→        }
175→
176→        set clip(value) {
177→            [this._clip_x0, this._clip_y0, this._clip_width, this._clip_height] = value;
178→            this.set_uniform_value('clip_x0', parseFloat(this._clip_x0 - 1e-6));
179→            this.set_uniform_value('clip_y0', parseFloat(this._clip_y0 - 1e-6));
180→            this.set_uniform_value('clip_width', parseFloat(this._clip_width <= 0 ? -1 : this._clip_width + 3 - 1e-6));
181→            this.set_uniform_value('clip_height', parseFloat(this._clip_height <= 0 ? -1 : this._clip_height + 3 - 1e-6));
182→            this.update_radius();
183→        }
184→
185→        vfunc_set_actor(actor) {
186→            if (this._actor_connection_size_id) {
187→                let old_actor = this.get_actor();
188→                old_actor?.disconnect(this._actor_connection_size_id);
189→            }
190→            if (this._actor_connection_clip_rect_id) {
191→                let old_actor = this.get_actor();
192→                old_actor?.disconnect(this._actor_connection_clip_rect_id);
193→            }
194→
195→            if (actor) {
196→                this.width = actor.width;
197→                this.height = actor.height;
198→                this._actor_connection_size_id = actor.connect('notify::size', _ => {
199→                    this.width = actor.width;
200→                    this.height = actor.height;
201→                });
202→
203→                this.clip = actor.has_clip ? actor.get_clip() : [0, 0, -10, -10];
204→                this._actor_connection_clip_rect_id = actor.connect('notify::clip-rect', _ => {
205→                    this.clip = actor.has_clip ? actor.get_clip() : [0, 0, -10, -10];
206→                });
207→            }
208→            else {
209→                this._actor_connection_size_id = null;
210→                this._actor_connection_clip_rect_id = null;
211→            }
212→
213→            super.vfunc_set_actor(actor);
214→        }
215→    });

