        strength = prefer_closer_pixels ? ((iterations + 1) * (iterations + 1)) : 1;
        c += strength * texture2D(tex, uv);
        count += strength;
    }

    c.xyz *= brightness;
    cogl_color_out = c / float(max(1, count));
}
    c.xyz *= brightness;
