vec4 getTexture(vec2 uv) {
    if (uv.x < 3. / width)
        uv.x = 3. / width;

    if (uv.y < 3. / height)
        uv.y = 3. / height;

    if (uv.x > 1. - 3. / width)
        uv.x = 1. - 3. / width;

    if (uv.y > 1. - 3. / height)
        uv.y = 1. - 3. / height;

    return texture2D(tex, uv);
}

args.new_string:
vec4 getTexture(vec2 uv) {
    float w = max(1.0, width);
    float h = max(1.0, height);

    if (uv.x < 3. / w)
        uv.x = 3. / w;

    if (uv.y < 3. / h)
        uv.y = 3. / h;

    if (uv.x > 1. - 3. / w)
        uv.x = 1. - 3. / w;

    if (uv.y > 1. - 3. / h)
        uv.y = 1. - 3. / h;

    return texture2D(tex, uv);
}

