args.content:
// Single-pass pixelize effect.
// This replaces the old fragile two-pass (downscale + upscale injected as siblings)
// which was very unreliable on panel/overview backgrounds and sometimes even popups.
//
// It produces the same visual "blocky" result by quantizing to a grid and
// (optionally) averaging inside each block.

uniform sampler2D tex;
uniform int factor;
uniform float width;
uniform float height;
uniform int downsampling_mode;
uniform float opacity_factor;

#define CORRECTION 2.25
#define SIZE_ADDITION 3

vec4 get_texture_at_position(vec2 position) {
    vec2 raw_position = position + vec2(CORRECTION, CORRECTION);
    vec2 raw_uv = raw_position / vec2(max(1.0, width + SIZE_ADDITION), max(1.0, height + SIZE_ADDITION));
    return texture2D(tex, raw_uv);
}

vec2 get_corrected_position() {
    vec2 raw_uv = cogl_tex_coord0_in.st;
    vec2 raw_position = raw_uv * vec2(width + SIZE_ADDITION, height + SIZE_ADDITION);
    return raw_position - vec2(CORRECTION, CORRECTION);
}

void main() {
    vec4 source_color = texture2D(tex, cogl_tex_coord0_in.st);

    if (factor <= 1) {
        cogl_color_out = mix(source_color, source_color, opacity_factor);
        return;
    }

    vec2 corrected = get_corrected_position();

    // Origin of the current pixel's block in corrected space
    vec2 block_origin = floor(corrected / float(factor)) * float(factor);

    vec4 effect_color = vec4(0.0);

    if (downsampling_mode == 2) {
        // Dirac / single representative sample (center of block) - fast & hard pixels
        vec2 center = block_origin + vec2(0.5 * float(factor));
        effect_color = get_texture_at_position(center);
    } else {
        // Average over the block (boxcar for mode 0, simple triangular-ish for mode 1)
        vec4 sum = vec4(0.0);
        float weight_sum = 0.0;
        int f = factor;

        for (int i = 0; i < f; i++) {
            for (int j = 0; j < f; j++) {
                vec2 pos = block_origin + vec2(float(i) + 0.5, float(j) + 0.5);

                float w = 1.0;
                if (downsampling_mode == 1) {
                    // Rough triangular weight towards center of the block
                    float di = abs(float(i) - float(f - 1) * 0.5);
                    float dj = abs(float(j) - float(f - 1) * 0.5);
                    w = max(0.1, float(f) * 0.5 - (di + dj) * 0.5);
                }

                sum += w * get_texture_at_position(pos);
                weight_sum += w;
            }
        }

        effect_color = sum / max(1.0, weight_sum);
    }

    cogl_color_out = mix(source_color, effect_color, opacity_factor);
}

args.old_string:
export const PixelizeEffect = utils.IS_IN_PREFERENCES ?
    { default_params: DEFAULT_PARAMS } :
    new GObject.registerClass({
        GTypeName: "PixelizeEffect",
        Properties: {
            'factor': GObject.ParamSpec.int(
                `factor`,
                `Factor`,
                `Factor`,
                GObject.ParamFlags.READWRITE,
                0, 64,
                8,
            ),
            'downsampling_mode': GObject.ParamSpec.int(
                `downsampling_mode`,
                `Downsampling mode`,
                `Downsampling mode`,
                GObject.ParamFlags.READWRITE,
                0, 2,
                0,
            ),
            'opacity_factor': GObject.ParamSpec.double(
                `opacity_factor`,
                `Opacity factor`,
                `Opacity factor`,
                GObject.ParamFlags.READWRITE,
                0.0, 1.0,
                1.0,
            )
        }
    }, class PixelizeEffect extends Clutter.Effect {
        constructor(params) {
            super();

            this.upscale_effect = new UpscaleEffect({});
            this.downscale_effect = new DownscaleEffect({});

            utils.setup_params(this, params);
        }

        static get default_params() {
            return DEFAULT_PARAMS;
        }

        get factor() {
            // should be the same as `this.downscale_effect.divider`
            return this.upscale_effect.factor;
        }

        set factor(value) {
            this.upscale_effect.factor = value;
            this.downscale_effect.divider = value;
        }

        get downsampling_mode() {
            return this.downscale_effect.downsampling_mode;
        }

        set downsampling_mode(value) {
            this.downscale_effect.downsampling_mode = value;
        }

        get opacity_factor() {
            return this._opacity_factor;
        }

        set opacity_factor(value) {
            if (this._opacity_factor !== value) {
                this._opacity_factor = value;
                this.upscale_effect.opacity_factor = value;
                this.downscale_effect.opacity_factor = value;
            }
        }

        vfunc_set_actor(actor) {
            // detach effects from old actor
            if (this._pixelize_size_id && this._pixelize_actor) {
                this._pixelize_actor.disconnect(this._pixelize_size_id);
                this._pixelize_size_id = null;
            }
            this.upscale_effect?.actor?.remove_effect(this.upscale_effect);
            this.downscale_effect?.actor?.remove_effect(this.downscale_effect);

            // attach effects to new actor.
            // Order is critical for the two-pass pixelize trick:
            // downscale must run first (processes original input, writes low-res to top-left),
            // then upscale runs on the result of downscale.
            if (actor) {
                if (this.downscale_effect) {
                    actor.add_effect(this.downscale_effect);
                }
                if (this.upscale_effect) {
                    actor.add_effect(this.upscale_effect);
                }

                // Explicitly push current size to children right after attachment.
                const w = actor.width || 1;
                const h = actor.height || 1;
                if (this.downscale_effect) {
                    this.downscale_effect.width = w;
                    this.downscale_effect.height = h;
                }
                if (this.upscale_effect) {
                    this.upscale_effect.width = w;
                    this.upscale_effect.height = h;
                }

                // Re-apply the other params synchronously too.
                if (this.downscale_effect) {
                    this.downscale_effect.divider = this.factor;
                    this.downscale_effect.downsampling_mode = this.downsampling_mode;
                    this.downscale_effect.opacity_factor = this.opacity_factor;
                }
                if (this.upscale_effect) {
                    this.upscale_effect.factor = this.factor;
                    this.upscale_effect.opacity_factor = this.opacity_factor;
                }

                // Kick once immediately.
                actor?.queue_repaint?.();

                // Schedule another sync after the actor has had a chance to fully
                // allocate (very common source of "pixelize does nothing" on
                // panel/overview backgrounds and sometimes popups).
                GLib.idle_add(GLib.PRIORITY_DEFAULT_IDLE, () => {
                    if (actor && !actor.is_destroyed?.()) {
                        const ww = actor.width || 1;
                        const hh = actor.height || 1;
                        if (this.downscale_effect) {
                            this.downscale_effect.width = ww;
                            this.downscale_effect.height = hh;
                            // Re-apply other params too in case the children were
                            // attached before the manager had its final values.
                            this.downscale_effect.divider = this.factor;
                            this.downscale_effect.downsampling_mode = this.downsampling_mode;
                            this.downscale_effect.opacity_factor = this.opacity_factor;
                        }
                        if (this.upscale_effect) {
                            this.upscale_effect.width = ww;
                            this.upscale_effect.height = hh;
                            this.upscale_effect.factor = this.factor;
                            this.upscale_effect.opacity_factor = this.opacity_factor;
                        }
                    }
                    // Kick the actor so the newly synced effects actually draw with the
                    // correct dimensions.
                    actor?.queue_repaint?.();
                    return GLib.SOURCE_REMOVE;
                });

                // Keep children in sync if the host actor resizes later.
                // The children also connect to notify::size themselves, but having the
                // container do it too is more reliable during complex background
                // management (panel, overview, multi-monitor, animations).
                this._pixelize_actor = actor;
                this._pixelize_size_id = actor.connect('notify::size', () => {
                    const ww = actor.width || 1;
                    const hh = actor.height || 1;
                    if (this.downscale_effect) {
                        this.downscale_effect.width = ww;
                        this.downscale_effect.height = hh;
                    }
                    if (this.upscale_effect) {
                        this.upscale_effect.width = ww;
                        this.upscale_effect.height = hh;
                    }
                });
            } else {
                this._pixelize_actor = null;
            }

            super.vfunc_set_actor(actor);
        }

        vfunc_set_enabled(is_enabled) {
            this.upscale_effect?.set_enabled(is_enabled);
            this.downscale_effect?.set_enabled(is_enabled);
            super.vfunc_set_enabled(is_enabled);
        }

        vfunc_dispose() {
            if (this._pixelize_size_id && this._pixelize_actor) {
                try { this._pixelize_actor.disconnect(this._pixelize_size_id); } catch (e) {}
            }
            this._pixelize_size_id = null;
            this._pixelize_actor = null;

            // Best-effort cleanup of injected children
            this.upscale_effect?.actor?.remove_effect(this.upscale_effect);
            this.downscale_effect?.actor?.remove_effect(this.downscale_effect);

            super.vfunc_dispose?.();
        }
    });

