    }, class PixelizeEffect extends Clutter.ShaderEffect {
        constructor(params) {
            super(params);

            // Load the self-contained single-pass shader.
            // This replaces the old fragile "inject Downscale + Upscale as siblings"
            // approach that never reliably worked on panel/overview (and sometimes popups).
            this._source = utils.get_shader_source(Shell, SHADER_FILENAME, import.meta.url);
            if (this._source) {
                this.set_shader_source(this._source);
            }

            utils.setup_params(this, params);
        }

        static get default_params() {
            return DEFAULT_PARAMS;
        }

        get factor() {
            return this._factor;
        }

        set factor(value) {
            if (this._factor !== value) {
                this._factor = value;
                this.set_uniform_value('factor', this._factor);
            }
        }

        get downsampling_mode() {
            return this._downsampling_mode;
        }

        set downsampling_mode(value) {
            if (this._downsampling_mode !== value) {
                this._downsampling_mode = value;
                this.set_uniform_value('downsampling_mode', this._downsampling_mode);
            }
        }

        get opacity_factor() {
            return this._opacity_factor;
        }

        set opacity_factor(value) {
            if (this._opacity_factor !== value) {
                this._opacity_factor = value;
                this.set_uniform_value('opacity_factor', parseFloat(this._opacity_factor));
            }
        }

        get width() {
            return this._width;
        }

        set width(value) {
            const v = Math.max(1, value || 1);
            if (this._width !== v) {
                this._width = v;
                this.set_uniform_value('width', parseFloat(this._width - 1e-6));
            }
        }

        get height() {
            return this._height;
        }

        set height(value) {
            const v = Math.max(1, value || 1);
            if (this._height !== v) {
                this._height = v;
                this.set_uniform_value('height', parseFloat(this._height - 1e-6));
            }
        }

        vfunc_set_actor(actor) {
            if (this._actor_connection_size_id) {
                let old_actor = this.get_actor();
                old_actor?.disconnect(this._actor_connection_size_id);
            }
            if (actor) {
                this.width = actor.width;
                this.height = actor.height;
                this._actor_connection_size_id = actor.connect('notify::size', _ => {
                    this.width = actor.width;
                    this.height = actor.height;
                });
            } else {
                this._actor_connection_size_id = null;
            }

            super.vfunc_set_actor(actor);
        }

        vfunc_paint_target(paint_node, paint_context) {
            // Force nearest filtering for crisp block edges (the shader does the
            // quantization, but nearest input helps a lot for the classic pixel look).
            const pipeline = this.get_pipeline();
            if (pipeline) {
                try {
                    pipeline.set_layer_filters(0, 9728, 9728);
                } catch (e) {}
            }

            super.vfunc_paint_target(paint_node, paint_context);
        }
    });

