args.old_string:
// Single-pass pixelize effect.
// This replaces the old fragile two-pass (downscale + upscale injected as siblings)
// which was very unreliable on panel/overview backgrounds and sometimes even popups.
//
// It produces the same visual "blocky" result by quantizing to a grid and
// (optionally) averaging inside each block.

uniform sampler2D tex;
uniform int factor;
uniform float width;
uniform float height;
uniform int downsampling_mode;
uniform float opacity_factor;

#define CORRECTION 2.25
#define SIZE_ADDITION 3

vec4 get_texture_at_position(vec2 position) {
    vec2 raw_position = position + vec2(CORRECTION, CORRECTION);
    vec2 raw_uv = raw_position / vec2(max(1.0, width + SIZE_ADDITION), max(1.0, height + SIZE_ADDITION));
    return texture2D(tex, raw_uv);
}

vec2 get_corrected_position() {
    vec2 raw_uv = cogl_tex_coord0_in.st;
    vec2 raw_position = raw_uv * vec2(width + SIZE_ADDITION, height + SIZE_ADDITION);
    return raw_position - vec2(CORRECTION, CORRECTION);
}

void main() {
    vec4 source_color = texture2D(tex, cogl_tex_coord0_in.st);

    if (factor <= 1) {
        cogl_color_out = mix(source_color, source_color, opacity_factor);
        return;
    }

    vec2 corrected = get_corrected_position();

    // Origin of the current pixel's block in corrected space
    vec2 block_origin = floor(corrected / float(factor)) * float(factor);

    vec4 effect_color = vec4(0.0);

    if (downsampling_mode == 2) {
        // Dirac / single representative sample (center of block) - fast & hard pixels
        vec2 center = block_origin + vec2(0.5 * float(factor));
        effect_color = get_texture_at_position(center);
    } else {
        // Average over the block (boxcar for mode 0, simple triangular-ish for mode 1)
        vec4 sum = vec4(0.0);
        float weight_sum = 0.0;
        int f = factor;

        for (int i = 0; i < f; i++) {
            for (int j = 0; j < f; j++) {
                vec2 pos = block_origin + vec2(float(i) + 0.5, float(j) + 0.5);

                float w = 1.0;
                if (downsampling_mode == 1) {
                    // Rough triangular weight towards center of the block
                    float di = abs(float(i) - float(f - 1) * 0.5);
                    float dj = abs(float(j) - float(f - 1) * 0.5);
                    w = max(0.1, float(f) * 0.5 - (di + dj) * 0.5);
                }

                sum += w * get_texture_at_position(pos);
                weight_sum += w;
            }
        }

        effect_color = sum / max(1.0, weight_sum);
    }

    cogl_color_out = mix(source_color, effect_color, opacity_factor);
}

args.new_string:
// Single-pass pixelize effect (robust version).
//
// The previous loop-based version (and the old two-child-injection hack)
// were causing GL_INVALID_OPERATION on many drivers when the effect was
// present, because of dynamic for-loops over a uniform and complex chained
// ShaderEffect state.
//
// This version is deliberately minimal and loop-free. It still gives a
// strong, clean pixelated/blocky look by quantizing coordinates to a grid.

uniform sampler2D tex;
uniform int factor;
uniform float width;
uniform float height;
uniform float opacity_factor;

#define CORRECTION 2.25
#define SIZE_ADDITION 3

vec4 get_texture_at_position(vec2 position) {
    vec2 raw_position = position + vec2(CORRECTION, CORRECTION);
    vec2 raw_uv = raw_position / vec2(max(1.0, width + SIZE_ADDITION), max(1.0, height + SIZE_ADDITION));
    return texture2D(tex, raw_uv);
}

vec2 get_corrected_position() {
    vec2 raw_uv = cogl_tex_coord0_in.st;
    vec2 raw_position = raw_uv * vec2(width + SIZE_ADDITION, height + SIZE_ADDITION);
    return raw_position - vec2(CORRECTION, CORRECTION);
}

void main() {
    vec4 source_color = texture2D(tex, cogl_tex_coord0_in.st);

    if (factor <= 1) {
        cogl_color_out = mix(source_color, source_color, opacity_factor);
        return;
    }

    vec2 corrected = get_corrected_position();

    // Quantize to block grid (this is what produces the visible pixels)
    vec2 block_origin = floor(corrected / float(factor)) * float(factor);

    // Sample once per block (center of the block). This is fast, compatible,
    // and gives the classic hard pixelated look. No loops, no dynamic bounds.
    vec2 representative = block_origin + vec2(0.5 * float(factor));

    vec4 effect_color = get_texture_at_position(representative);

    cogl_color_out = mix(source_color, effect_color, opacity_factor);
}

