args.new_string:
vec2 get_corrected_position() {
    // Use the array form (cogl_tex_coord_in[0]) which is used by the
    // majority of shaders in this extension and tends to be more reliable
    // across different effect chain positions.
    vec2 raw_uv = cogl_tex_coord_in[0].st;
    vec2 raw_position = raw_uv * vec2(width + SIZE_ADDITION, height + SIZE_ADDITION);
    return raw_position - vec2(CORRECTION, CORRECTION);
}

