vfunc_paint_target(paint_node, paint_context) {
    const t0 = Date.now();

    if (!this._logged_first_paint) {
        console.log(`[Blur my Shell] PixelizeEffect first paint on actor size ${this._width}x${this._height}, factor=${this._factor}, mode=${this._downsampling_mode}`);
        this._logged_first_paint = true;
    }

    // We upload uniforms *only* here. Any earlier calls (from setters or
    // vfunc_set_actor) during effect add/remove on background actors are
    // a known source of the 1282 errors you are seeing.
    try {
        this.set_uniform_value('factor', this._factor);
        this.set_uniform_value('downsampling_mode', this._downsampling_mode);
        this.set_uniform_value('opacity_factor', parseFloat(this._opacity_factor || 1));
        this.set_uniform_value('width', parseFloat((this._width || 1) - 1e-6));
        this.set_uniform_value('height', parseFloat((this._height || 1) - 1e-6));
    } catch (e) {
        console.warn('[Blur my Shell] PixelizeEffect uniform upload threw', e);
    }

    const t1 = Date.now();
    if (t1 - t0 > 5) {
        console.log(`[Blur my Shell] PixelizeEffect slow uniform upload: ${t1 - t0}ms`);
    }

    super.vfunc_paint_target(paint_node, paint_context);
}

